var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`......종신계약? 선생님이 종신 같은 단어는 조심하라던데요?`,JPN:`……終身契約？先生に、終身なんとかって言葉には気を付けろって言われましたよ。`,ENG:`A lifetime contract? But my teacher told me to watch for words like lifetime.`,TWN:`……終身契約？老師有說過，要小心終身這種話喔？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`아하하~ 장난이에요, 장난.`,JPN:`あはは～冗談ですよ、冗談。`,ENG:`Ah hah hah! No. I was just messing with you.`,TWN:`啊哈哈~開玩笑而已啦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`으음...... 그치만...... 여기 사인하면 학교 졸업하고 나서도 회사에 나와야 하는 거죠?`,JPN:`ううん……でも……ここにサインすれば、学校を卒業しても会社に行かなきゃいけないですよね？`,ENG:`Mm, but... if I sign this contract, I'll have to come to work here even after I graduate from the Academy, right?`,TWN:`嗯……但是……在這裡簽名的話，學校畢業後也得來公司吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`......결심! 역시 해야겠어!`,JPN:`……決めた！やっぱりやります！`,ENG:`Okay, I've made up my mind!`,TWN:`決定了！我果然得這麼做才行。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`회사 사람들이랑 여기저기 다니는 것도 즐겁고, 저희가 가는 침식지대엔 언제나 누군가의 도움이 필요한 동물들이 많이 있으니까요!`,JPN:`会社のみんなとあちこち行くのも楽しいし、僕たちが出向く侵食地帯には、いつも助けを求めている動物たちがいっぱいいますから！`,ENG:`It's fun to go around with people at the company. Besides, there are a lot of animals in Corrupted Areas that need help.`,TWN:`和公司的人一起去各種地方也很開心，而且我們去的侵蝕地區，總是會有很多動物需要幫顧嘛！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`고미랑 더쿠랑 토리도 친구들이 많아지면 좋아하겠죠?`,JPN:`クマたんとダック、トリも友達が増えたら喜ぶでしょうね。`,ENG:`Teddy, Ducky, and Hopper would love to have more friends, too.`,TWN:`咕美熊熊、托里還有德庫肯定也希望能交更多朋友吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`아 참, 대신 중간에 맘에 안 든다고 자르기 없기에요?`,JPN:`あ、そうだ。その代わり、気に入らなくても途中でクビにしないでくださいよ？`,ENG:`Oh, and you'd better not let me go later because you don't like me anymore. Promise?`,TWN:`啊對了，就算中途不滿意，你也不可以裁掉我喔？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HARIM_REBBIT_VAL_NULL`,text:{KOREA:`자아, 그럼 어디~`,JPN:`さあ、それじゃあやりますか～。`,ENG:`Alright, then...`,TWN:`那麼，讓我看看～`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HARIM_REBBIT_VAL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};